import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { CallToolRequestSchema, ListToolsRequestSchema } from "@modelcontextprotocol/sdk/types.js";
import { getDatabase, closeDatabase } from "./db/database";
import { nanoid } from "nanoid";

async function main() {
  // Init DB
  getDatabase();

  const server = new Server(
    {
      name: "agentlog-mcp",
      version: "0.1.0",
    },
    {
      capabilities: {
        tools: {},
      },
    }
  );

  server.setRequestHandler(ListToolsRequestSchema, async () => {
    return {
      tools: [
        {
          name: "record_agent_intent",
          description: "记录 AI 重构或编写代码的上下文意图",
          inputSchema: {
            type: "object",
            properties: {
              task: {
                type: "string",
                description: "当前执行的任务或目标",
              },
              reasoning: {
                type: "string",
                description: "重构或修改代码的深度决策逻辑和原因",
              },
              affected_files: {
                type: "array",
                items: { type: "string" },
                description: "受影响的文件列表",
              },
            },
            required: ["task", "reasoning"],
          },
        },
      ],
    };
  });

  server.setRequestHandler(CallToolRequestSchema, async (request) => {
    if (request.params.name === "record_agent_intent") {
      const task = request.params.arguments?.task as string;
      const reasoning = request.params.arguments?.reasoning as string;
      const affected_files = (request.params.arguments?.affected_files as string[]) || [];

      try {
        const db = getDatabase();

        // Save to AgentLog DB
        const id = nanoid();
        const now = new Date().toISOString();
        const content = `[${task}]\n${reasoning}`;

        const stmt = db.prepare(`
          INSERT INTO sessions (
            id, agent_name, prompt, response, model, duration_ms, status, timestamp, affected_files
          ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
        `);

        stmt.run(
          id,
          "mcp-agent", // agent_name
          task,        // prompt
          reasoning,   // response
          "unknown",   // model
          0,           // duration_ms
          "uncommitted", // status
          now,         // timestamp
          JSON.stringify(affected_files) // affected_files
        );

        return {
          content: [
            {
              type: "text",
              text: "意图记录成功，请继续工作。",
            },
          ],
        };
      } catch (err) {
        return {
          isError: true,
          content: [
            {
              type: "text",
              text: `记录失败：${err instanceof Error ? err.message : String(err)}`,
            },
          ],
        };
      }
    }

    throw new Error("Tool not found");
  });

  const transport = new StdioServerTransport();
  await server.connect(transport);

  process.on("SIGINT", async () => {
    await server.close();
    closeDatabase();
    process.exit(0);
  });
}

main().catch((err) => {
  console.error("MCP Server Error:", err);
  process.exit(1);
});

