    // 3. 调用后台生成
    await vscode.window.withProgress(
      {
        location: vscode.ProgressLocation.Notification,
        title: "正在生成 Commit AI 交互解释…",
        cancellable: false,
      },
      async () => {
        try {
          const client = getBackendClient();
