              .showErrorMessage(
                "AgentLog 后台服务未启动，无法生成解释",
                "启动服务",
              )
              .then((action) => {
                if (action === "启动服务") {
                  vscode.commands.executeCommand("agentlog.startBackend");
                }
              });
          } else {
            vscode.window.showErrorMessage(
              `生成解释失败：${err instanceof Error ? err.message : String(err)}`,
            );
          }
        }
      },
    );
  });
